const svg = $('#rvl-svg'), out = $('#rvl-out');
const W=760, H=260, pad=50;
const x0=pad, x1=W-pad, y0=40, y1=H-40;
// map [0,1] domain to pixels
const X = t => x0 + t*(x1-x0);
const Y = v => y1 - v*(y1-y0); // v in [0,1]
// generate "rationals" — fractions p/q with small q, dense enough visually
const rats = [];
for(let q=2;q<=20;q++){
  for(let p=1;p<q;p++){
    // reduced only
    const g=(a,b)=>b?g(b,a%b):a;
    if(g(p,q)!==1) continue;
    rats.push(p/q);
  }
}
rats.sort((a,b)=>a-b);

function baseAxes(mode){
  svg.innerHTML = '';
  // axes
  svg.appendChild(SVG('line',{x1:x0,y1:y1,x2:x1,y2:y1,stroke:'var(--line)','stroke-width':1.3}));
  svg.appendChild(SVG('line',{x1:x0,y1:y0,x2:x0,y2:y1,stroke:'var(--line)','stroke-width':1.3}));
  // tick labels on y
  const tk = [0,0.5,1];
  for(const v of tk){
    svg.appendChild(SVG('line',{x1:x0-4,y1:Y(v),x2:x0,y2:Y(v),stroke:'var(--mute)'}));
    const t=SVG('text',{x:x0-8,y:Y(v)+4,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
    t.textContent=v; svg.appendChild(t);
  }
  // x axis labels
  for(const v of [0,0.5,1]){
    const t=SVG('text',{x:X(v),y:y1+16,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
    t.textContent=v; svg.appendChild(t);
  }
  // draw Dirichlet rationals
  for(const r of rats){
    svg.appendChild(SVG('line',{x1:X(r),y1:Y(0),x2:X(r),y2:Y(1),
      stroke:'var(--cyan)','stroke-width':0.6,opacity:0.55}));
  }
  // title
  const t = SVG('text',{x:W/2,y:20,'text-anchor':'middle','font-size':13,fill:'var(--mute)'});
  t.textContent = mode;
  svg.appendChild(t);
}

function riemann(sampleKind){
  baseAxes('Riemann: partition x-axis into 20 subintervals; choose samples of type "'+sampleKind+'"');
  const N=20;
  let S=0;
  for(let k=0;k<N;k++){
    const a=k/N, b=(k+1)/N;
    // choose a sample in [a,b]
    // if rational: pick nearest rational in rats inside interval
    let xi=null;
    if(sampleKind==='rational'){
      for(const r of rats){ if(r>=a && r<b){ xi=r; break; } }
      if(xi===null) xi=(a+b)/2;       // fallback
    } else {
      // irrational sample: use a+(b-a)*1/pi (almost surely irrational)
      xi = a + (b-a)*(1/Math.PI);
    }
    const val = (sampleKind==='rational') ? 1 : 0;
    S += val * (b-a);
    // rectangle
    svg.appendChild(SVG('rect',{x:X(a),y:Y(val),width:X(b)-X(a),height:Y(0)-Y(val),
      fill: val? 'rgba(255,216,102,0.35)':'rgba(255,216,102,0.08)',
      stroke:'var(--yellow)','stroke-width':1}));
    // sample dot
    svg.appendChild(SVG('circle',{cx:X(xi),cy:Y(val),r:2.5,fill:'var(--yellow)'}));
  }
  out.textContent =
    sampleKind==='rational'
      ? 'Rational samples ⇒ every rectangle has height 1, Riemann sum = 1.\n'
        +'This is the upper Darboux sum — rationals dense in every subinterval.'
      : 'Irrational samples ⇒ every rectangle has height 0, Riemann sum = 0.\n'
        +'This is the lower Darboux sum — irrationals dense in every subinterval.\n'
        +'U = 1, L = 0 — the function is NOT Riemann-integrable.';
}

function lebesgue(){
  baseAxes('Lebesgue: partition y-axis. Two level sets: {f=0} and {f=1}.');
  // horizontal bands
  const bands = [
    {y:0, col:'rgba(131,193,103,0.25)', lbl:'{f = 0} (irrationals) — measure 1'},
    {y:1, col:'rgba(224,122,95,0.25)',  lbl:'{f = 1} (rationals) — measure 0'}
  ];
  // show full "mass" band on {f=0}: indicator shaded from 0→0 visually is nothing;
  // instead we display two coloured stripes across the whole x range meaning
  // "this entire x-range maps into this y-band".
  // stripe 1: f=0  — entire [0,1] minus a measure-0 set
  svg.appendChild(SVG('rect',{x:X(0),y:Y(0.04),width:X(1)-X(0),height:8,
    fill:'rgba(131,193,103,0.55)',stroke:'var(--green)'}));
  const t1 = SVG('text',{x:X(1)+8,y:Y(0.04)+6,'font-size':11,fill:'var(--green)'});
  t1.textContent = '{f=0}, measure = 1';
  svg.appendChild(t1);
  // stripe 2: f=1 — rationals only (measure 0, drawn as ticks)
  for(const r of rats){
    svg.appendChild(SVG('line',{x1:X(r),y1:Y(1)-4,x2:X(r),y2:Y(1)+4,
      stroke:'var(--pink)','stroke-width':1}));
  }
  const t2 = SVG('text',{x:X(1)+8,y:Y(1)+4,'font-size':11,fill:'var(--pink)'});
  t2.textContent = '{f=1}, measure = 0';
  svg.appendChild(t2);
  out.textContent =
    'Lebesgue: ∫ f dm = 0·m{f=0} + 1·m{f=1} = 0·1 + 1·0 = 0.\n'
    +'The rationals are countable, hence Lebesgue-measure 0. The irrationals have full measure.\n'
    +'1_{ℚ∩[0,1]} is Lebesgue integrable with integral 0.';
}

function reset(){ baseAxes('Dirichlet indicator 1_{ℚ∩[0,1]}: rationals shown as ticks, irrationals implicit.'); out.textContent='Pick a strategy.'; }

$('#rvl-rat').addEventListener('click',()=>riemann('rational'));
$('#rvl-irr').addEventListener('click',()=>riemann('irrational'));
$('#rvl-leb').addEventListener('click',lebesgue);
$('#rvl-reset').addEventListener('click',reset);
reset();

