/* =============================== §3 Outer measure covering demo =============================== */
(function(){
  const svg = $('#outer-svg'), out = $('#outer-out');
  const ws = $('#outer-w'), wv = $('#outer-wv');
  const W=760, H=260, pad=40;
  const xl=pad, xr=W-pad, yt=40, yb=H-pad;
  // target set E: union of three intervals (total length 0.6)
  const E = [[0.05,0.18],[0.34,0.52],[0.70,0.86]];
  const Eextent = E.reduce((s,[a,b])=>s+(b-a),0);
  const X = t => xl + t*(xr-xl);
  function draw(){
    const delta = +ws.value;
    wv.textContent = `δ = ${delta.toFixed(2)}`;
    svg.innerHTML = '';
    // axes
    svg.appendChild(SVG('line',{x1:xl,y1:yb,x2:xr,y2:yb,stroke:'var(--line)'}));
    for(const v of [0, 0.25, 0.5, 0.75, 1]){
      const t = SVG('text',{x:X(v),y:yb+14,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
      t.textContent = v.toFixed(2); svg.appendChild(t);
    }
    // draw target set E
    for(const [a,b] of E){
      svg.appendChild(SVG('rect',{x:X(a),y:yb-22,width:X(b)-X(a),height:16,
        fill:'rgba(125,224,214,0.30)',stroke:'var(--cyan)','stroke-width':1.2}));
    }
    const t0 = SVG('text',{x:xl,y:yb-28,'font-size':11,fill:'var(--cyan)'});
    t0.textContent = `target set E (total length = ${Eextent.toFixed(3)})`;
    svg.appendChild(t0);

    // greedy cover of E by open intervals of length ≤ δ centered on a grid step of size δ/2
    // place cover intervals starting at each E-component's left endpoint, width δ, step δ until past right endpoint
    const covers = [];
    for(const [a,b] of E){
      let x = a;
      while(x < b + 1e-9){
        covers.push([x - 0.005, x + delta - 0.005]); // tiny left slack so it's strictly open around a
        x += delta;
      }
    }
    let total = 0;
    for(const [a,b] of covers){
      total += (b - a);
      svg.appendChild(SVG('rect',{x:X(a),y:yt,width:X(b)-X(a),height:yb-yt-30,
        fill:'rgba(255,216,102,0.12)',stroke:'var(--yellow)','stroke-width':0.9}));
    }
    const t1 = SVG('text',{x:xl,y:yt-6,'font-size':11,fill:'var(--yellow)'});
    t1.textContent = `cover by ${covers.length} intervals of width δ — total length ${total.toFixed(3)}`;
    svg.appendChild(t1);

    out.textContent =
      `m(E) = ${Eextent.toFixed(3)}  (true Lebesgue measure)\n`+
      `cover length Σ(b_n - a_n) = ${total.toFixed(3)}   ≥ m*(E)\n`+
      `outer measure m*(E) = inf over all countable open covers of E.\n`+
      `As δ shrinks and covers become tighter, total length → ${Eextent.toFixed(3)} = m(E).`;
  }
  ws.addEventListener('input',draw);
  draw();
})();

