/* =============================== §5 Preimage viewer widget =============================== */
(function(){
  const svg = $('#preimage-svg'), out = $('#preimage-out');
  const as = $('#preimage-a'), bs = $('#preimage-b'), rv = $('#preimage-rv');
  const W=760, H=320, pad=40;
  const xl=pad, xr=W-pad, yt=30, yb=H-pad-30;
  const X = t => xl + t*(xr-xl);
  const Y = v => yb - v*(yb-yt);
  // f(x) = 0.5 + 0.4 sin(3 π x)
  const f = x => 0.5 + 0.4*Math.sin(3*Math.PI*x);

  function draw(){
    let a = +as.value, b = +bs.value;
    if(a > b) [a,b] = [b,a];
    rv.textContent = `window = [${a.toFixed(2)}, ${b.toFixed(2)}]`;
    svg.innerHTML = '';
    // axes
    svg.appendChild(SVG('line',{x1:xl,y1:yb,x2:xr,y2:yb,stroke:'var(--line)'}));
    svg.appendChild(SVG('line',{x1:xl,y1:yt,x2:xl,y2:yb,stroke:'var(--line)'}));
    // y tick labels
    for(const v of [0,0.25,0.5,0.75,1]){
      const t = SVG('text',{x:xl-6,y:Y(v)+4,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
      t.textContent = v.toFixed(2); svg.appendChild(t);
    }
    // x tick labels
    for(const v of [0,0.5,1]){
      const t = SVG('text',{x:X(v),y:yb+14,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
      t.textContent = v; svg.appendChild(t);
    }
    // draw [a,b] horizontal band in the codomain
    svg.appendChild(SVG('rect',{x:xl,y:Y(b),width:xr-xl,height:Y(a)-Y(b),
      fill:'rgba(179,157,219,0.18)',stroke:'var(--violet)','stroke-dasharray':'4 3','stroke-width':1}));
    const tlab = SVG('text',{x:xr-4,y:Y((a+b)/2)+4,'text-anchor':'end','font-size':11,fill:'var(--violet)'});
    tlab.textContent = `codomain window [a,b]`; svg.appendChild(tlab);
    // sample f over [0,1] and find preimage mask
    const Ns = 1500;
    const mask = new Array(Ns).fill(false);
    let hit = 0;
    for(let i=0;i<Ns;i++){
      const x = i/(Ns-1);
      const y = f(x);
      if(y >= a && y <= b){ mask[i] = true; hit++; }
    }
    const measure = hit/(Ns-1);
    // draw f curve
    let d='';
    for(let i=0;i<Ns;i++){
      const x=i/(Ns-1), y=f(x);
      d += (i? ' L':'M')+X(x).toFixed(2)+' '+Y(y).toFixed(2);
    }
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--cyan)','stroke-width':1.6}));
    // highlight preimage on x-axis
    let i=0;
    while(i<Ns){
      if(!mask[i]){ i++; continue; }
      let j=i;
      while(j<Ns && mask[j]) j++;
      const a0 = i/(Ns-1), b0 = (j-1)/(Ns-1);
