/* =============================== §5 Preimage viewer widget =============================== */
(function(){
  const svg = $('#preimage-svg'), out = $('#preimage-out');
  const as = $('#preimage-a'), bs = $('#preimage-b'), rv = $('#preimage-rv');
  const W=760, H=320, pad=40;
  const xl=pad, xr=W-pad, yt=30, yb=H-pad-30;
  const X = t => xl + t*(xr-xl);
  const Y = v => yb - v*(yb-yt);
  // f(x) = 0.5 + 0.4 sin(3 π x)
  const f = x => 0.5 + 0.4*Math.sin(3*Math.PI*x);

  function draw(){
    let a = +as.value, b = +bs.value;
    if(a > b) [a,b] = [b,a];
