    tx.textContent = `f^-1([a,b]) ⊂ [0,1] — highlighted on the x-axis`;
    svg.appendChild(tx);

    out.textContent =
      `f(x) = 0.5 + 0.4 sin(3πx),  window [a,b] = [${a.toFixed(2)}, ${b.toFixed(2)}]\n`+
      `m(f^{-1}([a,b])) ≈ ${measure.toFixed(4)}   (Lebesgue measure of preimage)\n`+
