const svg = $('#cantor-svg'), out = $('#cantor-out');
const slider = $('#cantor-k'), kv = $('#cantor-kv');
const W=760, H=240, pad=40;
function draw(){
  const k = +slider.value;
  kv.textContent = `k = ${k}`;
  svg.innerHTML = '';
  // draw iterations 0..k stacked vertically
  const rows = k+1;
  const rowH = (H - 2*pad) / Math.max(rows,1);
  // start from [0,1]
  let intervals = [[0,1]];
  for(let j=0;j<=k;j++){
    const y = pad + j*rowH + rowH*0.3;
    const h = Math.max(rowH*0.45, 6);
    for(const [a,b] of intervals){
      const x = pad + a*(W-2*pad);
      const w = (b-a)*(W-2*pad);
      svg.appendChild(SVG('rect',{x,y,width:w,height:h,
        fill:'var(--yellow)', opacity:0.85, stroke:'var(--yellow)'}));
    }
    // label
    const meas = Math.pow(2/3,j);
    const t=SVG('text',{x:pad-6,y:y+h*0.7,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
    t.textContent = `C_${j}  m=${meas.toFixed(4)}`;
    svg.appendChild(t);
    // next iteration: remove middle third
    const next = [];
    for(const [a,b] of intervals){
      const d=(b-a)/3;
      next.push([a, a+d]);
      next.push([b-d, b]);
    }
    intervals = next;
  }
  const meas = Math.pow(2/3,k);
  out.textContent =
    `After k = ${k} iterations:\n`+
    `  number of surviving intervals: 2^k = ${Math.pow(2,k)}\n`+
    `  each has length 3^-k = ${Math.pow(3,-k).toExponential(3)}\n`+
    `  total length m(C_k) = (2/3)^k = ${meas.toFixed(6)}\n`+
    `limit set C is uncountable (|C| = 2^ℵ₀) but m(C) = 0.`;
}
slider.addEventListener('input',draw);
draw();

