/* =============================== §3 Simple-function approximation =============================== */
(function(){
  const svg = $('#simple-svg'), out = $('#simple-out'), sel = $('#simple-n');
  const W=760, H=300, pad=40;
  const xl=pad, xr=W-pad, yt=20, yb=H-pad;
  const f = x => Math.sin(Math.PI*x) + 1;  // range [1,2] ⊂ [0,2]
  const YMAX = 2;
  const X = t => xl + t*(xr-xl);
  const Y = v => yb - (v/YMAX)*(yb-yt);

  function draw(){
    const n = +sel.value;
    svg.innerHTML = '';
    // axes
    svg.appendChild(SVG('line',{x1:xl,y1:yb,x2:xr,y2:yb,stroke:'var(--line)'}));
    svg.appendChild(SVG('line',{x1:xl,y1:yt,x2:xl,y2:yb,stroke:'var(--line)'}));
    // y ticks at each band boundary
    for(let k=0;k<=n;k++){
      const v = (k/n)*YMAX;
      svg.appendChild(SVG('line',{x1:xl-3,y1:Y(v),x2:xl,y2:Y(v),stroke:'var(--mute)'}));
    }
    // label extremes
    for(const v of [0,1,2]){
      const t=SVG('text',{x:xl-6,y:Y(v)+4,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
      t.textContent=v; svg.appendChild(t);
    }
    for(const v of [0,0.5,1]){
      const t=SVG('text',{x:X(v),y:yb+14,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
      t.textContent=v; svg.appendChild(t);
    }

    // For each band [k/n * YMAX, (k+1)/n * YMAX), find the x-subset mapped there,
    // highlight on x-axis; draw simple function bar at height k/n*YMAX over that subset.
    // f(x)=sin(πx)+1 is symmetric around x=1/2, increasing on [0,1/2], decreasing on [1/2,1].
    // Inverse on each half: for target y ∈ [0,2], sin(πx)=y-1 ⇒ x = arcsin(y-1)/π for left branch.
    const Ns = 400;
    // compute integral of simple function
    let simpleInt = 0;
    // build a color scale
    for(let k=0;k<n;k++){
      const yLow = (k/n)*YMAX, yHigh = ((k+1)/n)*YMAX;
      const barH = yLow;  // floor height of band (monotone from below)
      // for each x in [0,1], is f(x) ∈ [yLow, yHigh)?
      const mask = new Array(Ns).fill(false);
      let mLen = 0;
      for(let i=0;i<Ns;i++){
        const x = (i+0.5)/Ns;
        const fv = f(x);
        if(fv >= yLow && fv < yHigh){ mask[i]=true; mLen++; }
      }
      const measure = mLen/Ns;
      simpleInt += barH * measure;
      if(measure===0) continue;
      // draw simple bar at height barH on the mask
      // group contiguous runs
      let i=0;
      while(i<Ns){
        if(!mask[i]){ i++; continue; }
        let j=i;
        while(j<Ns && mask[j]) j++;
        const a = i/Ns, b = j/Ns;
        const col = `hsl(${40 + (k/Math.max(n-1,1))*200}, 65%, 55%)`;
        // bar
        svg.appendChild(SVG('rect',{x:X(a),y:Y(barH+YMAX/n),
          width:X(b)-X(a),height:Y(0)-Y(YMAX/n),
          fill:col,opacity:0.18,stroke:col,'stroke-width':0.6}));
        // highlight on x-axis
        svg.appendChild(SVG('line',{x1:X(a),y1:yb+2,x2:X(b),y2:yb+2,
          stroke:col,'stroke-width':3}));
        i=j;
      }
    }
    // draw the target curve on top
    let d='';
    for(let i=0;i<=Ns;i++){
      const x=i/Ns, y=f(x);
      d += (i? ' L':'M')+X(x)+' '+Y(y);
    }
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--cyan)','stroke-width':2}));
    // title
    const t = SVG('text',{x:W/2,y:14,'text-anchor':'middle','font-size':12,fill:'var(--mute)'});
    t.textContent = `n = ${n} bands: simple-function floor under f`;
    svg.appendChild(t);

    // exact integral ∫_0^1 (sin πx + 1) dx = 2/π + 1 ≈ 1.6366
    const exact = 2/Math.PI + 1;
    out.textContent =
      `bands n = ${n}\n`+
      `simple-function integral ∑ (k/n)·m{x: f(x)∈[k/n·2,(k+1)/n·2)} = ${simpleInt.toFixed(5)}\n`+
      `target ∫_0^1 (sin πx + 1) dx = 2/π + 1 = ${exact.toFixed(5)}\n`+
      `gap = ${(exact-simpleInt).toFixed(5)}   (→ 0 as n → ∞ by MCT)`;
  }
  sel.addEventListener('input',draw);
  draw();
})();

