/* =============================== §4 DCT demonstrator =============================== */
(function(){
  const svg = $('#dct-svg'), out = $('#dct-out');
  const pre = $('#dct-pre'), ns = $('#dct-n'), nv = $('#dct-nv');
  const W=760, H=300, pad=40;
  function draw(){
    const mode = pre.value, n = +ns.value;
    nv.textContent = `n = ${n}`;
    svg.innerHTML = '';
    const xl=pad, xr=W-pad, yt=20, yb=H-pad;
    let Xmax, Ymax;
    if(mode==='spike'){ Xmax=2; Ymax=Math.max(5, n+2); }
    else              { Xmax=2*Math.PI; Ymax=1.2; }
    const X = x => xl + (x/Xmax)*(xr-xl);
    const Y = v => yb - ((v+Ymax)/(2*Ymax))*(yb-yt);

    // axes
    svg.appendChild(SVG('line',{x1:xl,y1:(yb+yt)/2,x2:xr,y2:(yb+yt)/2,stroke:'var(--line)'}));
    svg.appendChild(SVG('line',{x1:xl,y1:yt,x2:xl,y2:yb,stroke:'var(--line)'}));

    // labels
    for(const tv of [0, Xmax/2, Xmax]){
      const t=SVG('text',{x:X(tv),y:yb+14,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
      t.textContent=tv.toFixed(Xmax===2?1:2); svg.appendChild(t);
    }

    // plot f_n
    const Ns = 1000;
    let d='', integ=0;
    if(mode==='spike'){
      // f_n(x) = n * 1_[0,1/n]
      // draw rectangle
      const a=0, b=1/n, h=n;
      svg.appendChild(SVG('rect',{x:X(a),y:Y(h),width:X(b)-X(a),height:Y(0)-Y(h),
        fill:'rgba(224,122,95,0.35)',stroke:'var(--pink)','stroke-width':1.4}));
      integ = 1;
      // pointwise limit = 0
      svg.appendChild(SVG('line',{x1:xl,y1:Y(0),x2:xr,y2:Y(0),
        stroke:'var(--green)','stroke-width':1,'stroke-dasharray':'4 4'}));
      const t=SVG('text',{x:xr-4,y:Y(0)-6,'text-anchor':'end','font-size':11,fill:'var(--green)'});
      t.textContent='pointwise limit = 0'; svg.appendChild(t);
    } else {
      // g_n(x) = sin(nx)/n
      integ = 0;
      for(let i=0;i<=Ns;i++){
        const x=(i/Ns)*Xmax;
        const v=Math.sin(n*x)/n;
        if(i) integ += v * (Xmax/Ns);
        d += (i? ' L':'M')+X(x)+' '+Y(v);
      }
      svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--pink)','stroke-width':1.5}));
      // dominator ±1/n
      const dom = 1/n;
      svg.appendChild(SVG('line',{x1:xl,y1:Y(dom),x2:xr,y2:Y(dom),
        stroke:'var(--violet)','stroke-width':1,'stroke-dasharray':'3 3'}));
      svg.appendChild(SVG('line',{x1:xl,y1:Y(-dom),x2:xr,y2:Y(-dom),
        stroke:'var(--violet)','stroke-width':1,'stroke-dasharray':'3 3'}));
      const t=SVG('text',{x:xr-4,y:Y(dom)-4,'text-anchor':'end','font-size':11,fill:'var(--violet)'});
      t.textContent=`±1/n dominator (integrable)`; svg.appendChild(t);
    }
    // title
    const tt = SVG('text',{x:W/2,y:14,'text-anchor':'middle','font-size':12,fill:'var(--mute)'});
    tt.textContent = mode==='spike'
      ? 'height n, width 1/n: ∫ = 1 for every n, yet f_n → 0 pointwise'
      : 'sin(nx)/n: uniformly small, ∫ → 0';
    svg.appendChild(tt);

    if(mode==='spike'){
      out.textContent =
        `f_n(x) = n · 1_{[0, 1/n]}(x), integrated on [0,2]\n`+
        `∫ f_n dm = n · (1/n) = 1   for every n.\n`+
        `f_n(x) → 0 for every x > 0 (and the single point x=0 is null).\n`+
        `so lim ∫ f_n = 1 ≠ 0 = ∫ lim f_n.\n`+
        `DCT fails: no integrable g with |f_n| ≤ g — sup_n f_n ~ 1/x near 0, not integrable.`;
    } else {
      out.textContent =
        `g_n(x) = sin(nx)/n on [0, 2π]\n`+
        `|g_n(x)| ≤ 1/n ≤ 1 = integrable dominator on a finite-measure space.\n`+
        `∫_0^{2π} g_n dm = (1 - cos(2πn))/n² = ${integ.toExponential(3)}\n`+
        `DCT applies: lim ∫ g_n = 0 = ∫ lim g_n.`;
    }
  }
  pre.addEventListener('change',draw);
  ns.addEventListener('input',draw);
  draw();
})();

