(function(){
  const svg = $('#product-svg'), out = $('#product-out');
  const axs = $('#product-ax'), bys = $('#product-by');
  const W=760, H=300, pad=40;
  const xl=pad+120, xr=W-pad, yt=30, yb=H-pad;
  const X = t => xl + t*(xr-xl);
  const Y = v => yb - v*(yb-yt);
  function draw(){
    const a = +axs.value, b = +bys.value;
    svg.innerHTML = '';
    // axes for x and y
    svg.appendChild(SVG('line',{x1:xl,y1:yb,x2:xr,y2:yb,stroke:'var(--line)'}));
