    // background square [0,1]^2
    svg.appendChild(SVG('rect',{x:X(0),y:Y(1),width:X(1)-X(0),height:Y(0)-Y(1),
      fill:'rgba(255,255,255,0.02)',stroke:'var(--line)','stroke-dasharray':'3 3'}));
    // rectangle A×B in [0,a]×[0,b]
    svg.appendChild(SVG('rect',{x:X(0),y:Y(b),width:X(a)-X(0),height:Y(0)-Y(b),
      fill:'rgba(131,193,103,0.22)',stroke:'var(--green)','stroke-width':1.5}));
    // shade A on x-axis and B on y-axis
    svg.appendChild(SVG('rect',{x:X(0),y:yb+4,width:X(a)-X(0),height:8,
      fill:'var(--yellow)',stroke:'var(--yellow)'}));
    svg.appendChild(SVG('rect',{x:xl-12,y:Y(b),width:8,height:Y(0)-Y(b),
      fill:'var(--cyan)',stroke:'var(--cyan)'}));
    // ticks
    for(const v of [0, 0.5, 1]){
      const t1 = SVG('text',{x:X(v),y:yb+28,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
      t1.textContent = v; svg.appendChild(t1);
      const t2 = SVG('text',{x:xl-20,y:Y(v)+4,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
      t2.textContent = v; svg.appendChild(t2);
    }
    // legend
    const lx = 30, ly = yt+10;
    const lg = SVG('text',{x:lx,y:ly,'font-size':12,fill:'var(--yellow)'});
    lg.textContent = `μ(A) = ${a.toFixed(3)}`;
    svg.appendChild(lg);
    const lg2 = SVG('text',{x:lx,y:ly+22,'font-size':12,fill:'var(--cyan)'});
    lg2.textContent = `ν(B) = ${b.toFixed(3)}`;
    svg.appendChild(lg2);
    const lg3 = SVG('text',{x:lx,y:ly+54,'font-size':12,fill:'var(--green)'});
    lg3.textContent = `(μ⊗ν)(A×B)`;
    svg.appendChild(lg3);
    const lg4 = SVG('text',{x:lx,y:ly+70,'font-size':14,fill:'var(--green)','font-weight':600});
    lg4.textContent = `= μ(A)·ν(B) = ${(a*b).toFixed(4)}`;
    svg.appendChild(lg4);

    out.textContent =
      `Rectangle A×B = [0, ${a.toFixed(3)}] × [0, ${b.toFixed(3)}]\n`+
      `(μ⊗ν)(A×B) = μ(A)·ν(B) = ${a.toFixed(3)} · ${b.toFixed(3)} = ${(a*b).toFixed(5)}\n`+
      `σ-finiteness gives the unique extension to all of 𝓐⊗𝓑. On non-rectangles, Carathéodory fills in the rest.`;
  }
  axs.addEventListener('input',draw);
  bys.addEventListener('input',draw);
  draw();
})();

