    svg.appendChild(SVG('line',{x1:xl,y1:yb,x2:xr,y2:yb,stroke:'var(--line)'}));
    svg.appendChild(SVG('line',{x1:xl,y1:yt,x2:xl,y2:yb,stroke:'var(--line)'}));
    for(const v of [0,0.5,1]){
      const tx = SVG('text',{x:X(v),y:yb+16,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
      tx.textContent = v; svg.appendChild(tx);
      const ty = SVG('text',{x:xl-6,y:Y(v)+4,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
      ty.textContent = v; svg.appendChild(ty);
    }
    // boundary: x^α + y^α = 1, quadrant
    let d = '';
    const Npt = 200;
    for(let i=0;i<=Npt;i++){
      const x = i/Npt;
      const yr = Math.pow(Math.max(1 - Math.pow(x,alpha),0), 1/alpha);
      d += (i? ' L':'M')+X(x).toFixed(2)+' '+Y(yr).toFixed(2);
    }
    // fill
    svg.appendChild(SVG('path',{d:d+` L${X(1)} ${Y(0)} L${X(0)} ${Y(0)} Z`,
      fill:'rgba(125,224,214,0.18)',stroke:'var(--cyan)','stroke-width':1.4}));
    // draw iteration strips
    const Nstrips = 18;
    let area = 0;
    if(mode === 'xy'){
      // outer dy, strips horizontal
      for(let k=0;k<Nstrips;k++){
        const y0 = k/Nstrips, y1 = (k+1)/Nstrips;
        const xmax = Math.pow(Math.max(1 - Math.pow((y0+y1)/2, alpha), 0), 1/alpha);
        if(xmax <= 0) continue;
        area += xmax / Nstrips;
        svg.appendChild(SVG('rect',{x:X(0),y:Y(y1),width:X(xmax)-X(0),height:Y(y0)-Y(y1),
          fill:'rgba(255,216,102,0.22)',stroke:'var(--yellow)','stroke-width':0.8}));
      }
    } else {
      // outer dx, strips vertical
      for(let k=0;k<Nstrips;k++){
        const x0 = k/Nstrips, x1 = (k+1)/Nstrips;
        const ymax = Math.pow(Math.max(1 - Math.pow((x0+x1)/2, alpha), 0), 1/alpha);
        if(ymax <= 0) continue;
        area += ymax / Nstrips;
        svg.appendChild(SVG('rect',{x:X(x0),y:Y(ymax),width:X(x1)-X(x0),height:Y(0)-Y(ymax),
          fill:'rgba(224,122,95,0.22)',stroke:'var(--pink)','stroke-width':0.8}));
      }
    }
    // title
    const t = SVG('text',{x:(xl+xr)/2,y:16,'text-anchor':'middle','font-size':12,fill:'var(--mute)'});
    t.textContent = `region R_α:  x,y≥0,  x^α + y^α ≤ 1   — iterated by ${mode==='xy'?'∫dy ∫dx':'∫dx ∫dy'}`;
    svg.appendChild(t);

    // exact area via Beta: ∫_0^1 (1-x^α)^(1/α) dx = (1/α)·B(1/α, 1 + 1/α) = Γ(1+1/α)²/Γ(1+2/α)
    // compute via numerical integration for display:
    let exact = 0, Nh = 2000;
    for(let i=0;i<Nh;i++){
      const x = (i+0.5)/Nh;
      exact += Math.pow(Math.max(1 - Math.pow(x,alpha), 0), 1/alpha) / Nh;
    }

    out.textContent =
      `α = ${alpha.toFixed(2)},  order = ${mode==='xy' ? 'dx then dy' : 'dy then dx'}\n`+
      `Riemann-approximated iterated integral with ${Nstrips} strips = ${area.toFixed(4)}\n`+
      `finer Riemann sum (N=${Nh}) = ${exact.toFixed(4)}\n`+
      `Tonelli: both orders agree for 1_{R_α} ≥ 0 — the integrand is automatic, no integrability check needed.`;
  }
  as_.addEventListener('input',draw);
  ord.addEventListener('change',draw);
  draw();
})();

/* =============================== §11 Radon-Nikodym density widget =============================== */
(function(){
  const svg = $('#rn-svg'), out = $('#rn-out');
  const cs = $('#rn-c'), ss = $('#rn-s');
  const W=760, H=320, pad=40;
  const xl=pad, xr=W-pad, yt=30, yb=H-pad-40;
  const X = t => xl + t*(xr-xl);
  let YMAX = 5;
  const Y = v => yb - (v/YMAX)*(yb-yt);
  function draw(){
    const c = +cs.value, s = +ss.value;
    svg.innerHTML = '';
    // f(x) = c · exp(-10 (x-s)^2), i.e., a bump centered at s
    const f = x => c * Math.exp(-10 * (x - s) ** 2);
    // axes
    svg.appendChild(SVG('line',{x1:xl,y1:yb,x2:xr,y2:yb,stroke:'var(--line)'}));
    svg.appendChild(SVG('line',{x1:xl,y1:yt,x2:xl,y2:yb,stroke:'var(--line)'}));
    for(const v of [0,1,2,3,4,5]){
      const ty = SVG('text',{x:xl-6,y:Y(v)+4,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
      ty.textContent = v; svg.appendChild(ty);
      svg.appendChild(SVG('line',{x1:xl-3,y1:Y(v),x2:xl,y2:Y(v),stroke:'var(--mute)'}));
    }
    for(const v of [0,0.5,1]){
      const tx = SVG('text',{x:X(v),y:yb+14,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
      tx.textContent = v; svg.appendChild(tx);
    }
    // shaded area
    const Npt = 800;
    let dPath = `M${X(0)} ${Y(0)}`;
    let total = 0;
    for(let i=0;i<=Npt;i++){
      const x = i/Npt, y = Math.min(f(x), YMAX);
      dPath += ` L${X(x).toFixed(2)} ${Y(y).toFixed(2)}`;
      if(i>0){ total += f((i-0.5)/Npt) / Npt; }
    }
    dPath += ` L${X(1)} ${Y(0)} Z`;
    svg.appendChild(SVG('path',{d:dPath,fill:'rgba(125,224,214,0.22)',stroke:'var(--cyan)','stroke-width':1.5}));
    // density curve
    let dc = '';
    for(let i=0;i<=Npt;i++){
      const x = i/Npt, y = Math.min(f(x), YMAX);
      dc += (i? ' L':'M')+X(x).toFixed(2)+' '+Y(y).toFixed(2);
    }
    svg.appendChild(SVG('path',{d:dc,fill:'none',stroke:'var(--cyan)','stroke-width':2}));

    // ν on x-axis: thickness proportional to f
    for(let i=0;i<Npt;i+=8){
      const x = (i+0.5)/Npt, y = f(x);
      const t = Math.min(1, y/YMAX);
      svg.appendChild(SVG('line',{x1:X(x),y1:yb+4,x2:X(x),y2:yb+4+2+t*18,
        stroke:'var(--green)','stroke-width':1,opacity:0.5+0.4*t}));
    }
    const tm = SVG('text',{x:xl,y:yb+42,'font-size':11,fill:'var(--green)'});
    tm.textContent = 'ν concentrates near high-density regions';
    svg.appendChild(tm);

    out.textContent =
      `density f(x) = dν/dm = ${c.toFixed(2)} · exp(-10 (x − ${s.toFixed(2)})²)\n`+
      `ν([0,1]) = ∫_0^1 f dm ≈ ${total.toFixed(4)}\n`+
      `ν is absolutely continuous w.r.t. m:  m(E)=0 ⇒ ν(E)=0 (integrating f over a null set gives 0).\n`+
      `Radon–Nikodym says every ν ≪ m is of this form (m-a.e. unique density).`;
  }
  cs.addEventListener('input',draw);
  ss.addEventListener('input',draw);
  draw();
})();

