/* =============================== §12 Riesz functional/measure selector =============================== */
(function(){
  const svg = $('#riesz-svg'), out = $('#riesz-out');
  const mode = $('#riesz-mode'), pa = $('#riesz-pick'), pv = $('#riesz-pv');
  const W=760, H=280, pad=40;
  const xl=pad, xr=W-pad, yt=30, yb=H-pad-30;
  const X = t => xl + t*(xr-xl);
  function draw(){
    const m = mode.value;
    const a = Math.max(0, Math.min(1, +pa.value));
    const b = Math.min(1, a + 0.25);
    pv.textContent = `[a,b] = [${a.toFixed(2)}, ${b.toFixed(2)}]`;
    svg.innerHTML = '';
    svg.appendChild(SVG('line',{x1:xl,y1:yb,x2:xr,y2:yb,stroke:'var(--line)'}));
    for(const v of [0,0.5,1]){
      const tx = SVG('text',{x:X(v),y:yb+14,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
      tx.textContent = v; svg.appendChild(tx);
    }
    // draw test interval [a,b]
    svg.appendChild(SVG('rect',{x:X(a),y:yb-24,width:X(b)-X(a),height:20,
      fill:'rgba(179,157,219,0.25)',stroke:'var(--violet)','stroke-width':1.2}));
    const tlab = SVG('text',{x:(X(a)+X(b))/2,y:yb-30,'text-anchor':'middle','font-size':11,fill:'var(--violet)'});
    tlab.textContent = 'test f = 𝟙_[a,b]'; svg.appendChild(tlab);
    // draw the measure visually
    let Lf, description, muDesc;
    if(m === 'dirac'){
      // delta at 1/2
      svg.appendChild(SVG('line',{x1:X(0.5),y1:yb-80,x2:X(0.5),y2:yb,stroke:'var(--pink)','stroke-width':2.4}));
      svg.appendChild(SVG('circle',{cx:X(0.5),cy:yb-80,r:5,fill:'var(--pink)'}));
      const t = SVG('text',{x:X(0.5)+8,y:yb-72,'font-size':11,fill:'var(--pink)'});
      t.textContent = 'μ = δ_{1/2}'; svg.appendChild(t);
      Lf = (0.5 >= a && 0.5 <= b) ? 1 : 0;
      muDesc = 'unit point mass at 1/2';
      description = `Λf = f(1/2).  For f = 𝟙_[a,b]:  Λf = 𝟙_[a,b](1/2) = ${Lf}.`;
    } else if(m === 'leb'){
      // Lebesgue density 1
      svg.appendChild(SVG('rect',{x:X(0),y:yb-50,width:X(1)-X(0),height:46,
        fill:'rgba(125,224,214,0.22)',stroke:'var(--cyan)','stroke-width':1}));
      const t = SVG('text',{x:X(1)-8,y:yb-56,'text-anchor':'end','font-size':11,fill:'var(--cyan)'});
      t.textContent = 'μ = m (Lebesgue)'; svg.appendChild(t);
      Lf = b - a;
      muDesc = 'Lebesgue measure on [0,1]';
      description = `Λf = ∫f dm.  For f = 𝟙_[a,b]:  Λf = b − a = ${Lf.toFixed(3)}.`;
    } else if(m === 'sum'){
      svg.appendChild(SVG('line',{x1:X(0.25),y1:yb-60,x2:X(0.25),y2:yb,stroke:'var(--pink)','stroke-width':2.4}));
      svg.appendChild(SVG('line',{x1:X(0.75),y1:yb-60,x2:X(0.75),y2:yb,stroke:'var(--pink)','stroke-width':2.4}));
      svg.appendChild(SVG('circle',{cx:X(0.25),cy:yb-60,r:4.5,fill:'var(--pink)'}));
      svg.appendChild(SVG('circle',{cx:X(0.75),cy:yb-60,r:4.5,fill:'var(--pink)'}));
      const t = SVG('text',{x:X(0.5),y:yb-70,'text-anchor':'middle','font-size':11,fill:'var(--pink)'});
      t.textContent = 'μ = ½ δ_{1/4} + ½ δ_{3/4}'; svg.appendChild(t);
      Lf = 0;
      if(0.25 >= a && 0.25 <= b) Lf += 0.5;
      if(0.75 >= a && 0.75 <= b) Lf += 0.5;
      muDesc = 'two atoms of mass 1/2 each';
      description = `Λf = ½ f(1/4) + ½ f(3/4).  For f = 𝟙_[a,b]:  Λf = ${Lf.toFixed(3)}.`;
    } else {
      // weighted density 2x
      const Npt = 400;
      let dpath = `M${X(0)} ${yb}`;
      for(let i=0;i<=Npt;i++){
        const x = i/Npt, y = 2*x;
        dpath += ` L${X(x).toFixed(2)} ${(yb - y*40).toFixed(2)}`;
      }
      dpath += ` L${X(1)} ${yb} Z`;
      svg.appendChild(SVG('path',{d:dpath,fill:'rgba(255,216,102,0.22)',stroke:'var(--yellow)','stroke-width':1.5}));
      const t = SVG('text',{x:X(1)-8,y:yb-80,'text-anchor':'end','font-size':11,fill:'var(--yellow)'});
      t.textContent = 'dμ = 2x dm'; svg.appendChild(t);
      Lf = b*b - a*a;
      muDesc = 'absolutely continuous, density 2x';
      description = `Λf = ∫₀¹ f(x)·2x dx.  For f = 𝟙_[a,b]:  Λf = b² − a² = ${Lf.toFixed(3)}.`;
    }
    out.textContent =
      `${description}\n`+
      `Represented by μ = ${muDesc}.\n`+
      `Riesz: every positive Λ on C_c corresponds to a unique regular Borel μ.`;
  }
  mode.addEventListener('change',draw);
  pa.addEventListener('input',draw);
  draw();
})();

