  const ss = $('#hausdorff-s'), sel = $('#hausdorff-set'), sv = $('#hausdorff-sv');
  const W=760, H=320, pad=40;
  const xl=pad+60, xr=W-pad, yt=30, yb=H-pad;
  const sets = {
