    koch:    {N:4, r:1/3, dim: Math.log(4)/Math.log(3)},
    gasket:  {N:3, r:1/2, dim: Math.log(3)/Math.log(2)}
  };
  function draw(){
    const s = +ss.value;
    sv.textContent = `s = ${s.toFixed(2)}`;
    svg.innerHTML = '';
    const key = sel.value;
    const {N, r, dim} = sets[key];
    // axes (k on x, log mass on y)
    const Kmax = 12;
    const xscale = (xr - xl) / Kmax;
    const yOffset = (yb + yt) / 2;
    const yScale = 22;
    svg.appendChild(SVG('line',{x1:xl,y1:yOffset,x2:xr,y2:yOffset,stroke:'var(--line)','stroke-dasharray':'3 3'}));
    svg.appendChild(SVG('line',{x1:xl,y1:yt,x2:xl,y2:yb,stroke:'var(--line)'}));
    // y tick
    for(const v of [-6, -3, 0, 3, 6]){
      const y = yOffset - v*yScale/2;
      const t = SVG('text',{x:xl-6,y:y+4,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
      t.textContent = `10^${v}`;
      svg.appendChild(t);
    }
    // x ticks
    for(let k=0;k<=Kmax;k+=2){
      const tx = SVG('text',{x:xl + k*xscale,y:yb+14,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
      tx.textContent = k; svg.appendChild(tx);
    }
    // title
    const tt = SVG('text',{x:(xl+xr)/2,y:16,'text-anchor':'middle','font-size':12,fill:'var(--mute)'});
    tt.textContent = `log₁₀ (N^k · r^{ks})  vs  iteration k  — ${key} (N=${N}, r=${r.toFixed(3)})`;
    svg.appendChild(tt);
    // data
    const logBase = Math.log(10);
    // mass at stage k = N^k · r^{ks}; log10 = k·(log N + s log r)
    let pts = [];
    for(let k=0;k<=Kmax;k++){
      const logM = k * (Math.log(N) + s*Math.log(r)) / logBase;
      const x = xl + k*xscale, y = yOffset - logM*yScale/2;
      pts.push([x, y, logM]);
    }
    // line + dots
    let d = '';
    for(let i=0;i<pts.length;i++){
      const [x,y] = pts[i];
      d += (i? ' L':'M')+x.toFixed(2)+' '+y.toFixed(2);
    }
    const col = s < dim ? 'var(--pink)' : s > dim ? 'var(--cyan)' : 'var(--green)';
    svg.appendChild(SVG('path',{d,fill:'none',stroke:col,'stroke-width':2}));
    for(const [x,y] of pts){
      svg.appendChild(SVG('circle',{cx:x,cy:y,r:2.2,fill:col}));
    }
    // critical-line marker at dim
    const lcrit = SVG('text',{x:xr-4,y:yt+14,'text-anchor':'end','font-size':11,fill:'var(--green)'});
    lcrit.textContent = `dim_H = log N / log(1/r) = ${dim.toFixed(4)}`;
    svg.appendChild(lcrit);

    const verdict = s < dim
      ? `s = ${s.toFixed(2)} < dim_H. Mass N^k r^{ks} → ∞, so H^s = ∞ (cover sum diverges).`
      : s > dim
      ? `s = ${s.toFixed(2)} > dim_H. Mass N^k r^{ks} → 0, so H^s = 0 (cover sum vanishes).`
      : `s = ${s.toFixed(2)} = dim_H. Mass N^k r^{ks} is constant (= 1), so 0 < H^s < ∞ at the critical dimension.`;
    out.textContent =
      `set = ${key};  similarity: N = ${N}, r = ${r.toFixed(4)};  Hausdorff dim = log N / log(1/r) = ${dim.toFixed(5)}.\n`+
      `At stage k, natural cover mass = N^k · r^{ks};  log₁₀ at k=${Kmax} is ${(Kmax*(Math.log(N)+s*Math.log(r))/Math.log(10)).toFixed(3)}.\n`+
      verdict;
  }
  ss.addEventListener('input',draw);
  sel.addEventListener('change',draw);
  draw();
})();

